 // ─── Queue in JavaScript ────────────────────────────────────────────────────
//
// JavaScript has no built-in queue. Arrays can simulate one but shift() is O(n)
// (shifts every element left). A proper O(1) queue uses a doubly linked list
// or a circular buffer. collections.deque equivalent: use two stacks or a
// custom class below.
// ── Simple queue using a singly linked list (O(1) enqueue + dequeue) ─────
class Node {
  constructor(value) { this.value = value; this.next = null;
    }
}

class Queue {
  constructor() {
    this.head = null; // front — dequeue here
    this.tail = null; // rear  — enqueue here
    this.size = 0;
    }
    // O(1) — Enqueue (add to rear)
  enqueue(value) {
    const node = new Node(value);
    if (!this.tail) { this.head = this.tail = node;
        }
    else { this.tail.next = node; this.tail = node;
        }
    this.size++;
    }
    // O(1) — Dequeue (remove from front)
  dequeue() {
    if (!this.head) throw new Error('Queue underflow');
    const val = this.head.value;
    this.head = this.head.next;
    if (!this.head) this.tail = null;
    this.size--;
    return val;
    }
    // O(1) — Peek front
  peek()    { if (!this.head) throw new Error('Empty'); return this.head.value;
    }
  isEmpty() { return this.size === 0;
    }
}
// ── Circular buffer queue (fixed capacity, O(1) all ops) ─────────────────
class CircularQueue {
  constructor(capacity) {
    this.buf  = new Array(capacity);
    this.cap  = capacity;
    this.front = 0;
    this.rear  = -1;
    this.count = 0;
    }

  enqueue(value) {
    if (this.count === this.cap) throw new Error('Queue full');
    this.rear = (this.rear + 1) % this.cap; // wrap around
    this.buf[this.rear
        ] = value;
    this.count++;
    }

  dequeue() {
    if (this.count === 0) throw new Error('Queue empty');
    const val = this.buf[this.front
        ];
    this.front = (this.front + 1) % this.cap; // wrap around
    this.count--;
    return val;
    }

  peek()    { return this.buf[this.front
        ];
    }
  isEmpty() { return this.count === 0;
    }
  isFull()  { return this.count === this.cap;
    }
}
// ── Priority queue using a min-heap ──────────────────────────────────────
class MinHeapPQ {
  constructor() { this.heap = [];
    }

  enqueue(value, priority) {
    this.heap.push({ value, priority
        });
    this._bubbleUp(this.heap.length - 1);
    }

  dequeue() {
    if (!this.heap.length) throw new Error('Empty');
    const min = this.heap[
            0
        ];
    const last = this.heap.pop();
    if (this.heap.length) { this.heap[
                0
            ] = last; this._sinkDown(0);
        }
    return min.value;
    }

  _bubbleUp(i) {
    while (i > 0) {
      const p = Math.floor((i - 1) / 2);
      if (this.heap[p
            ].priority <= this.heap[i
            ].priority) break;
      [this.heap[p
                ], this.heap[i
                ]
            ] = [this.heap[i
                ], this.heap[p
                ]
            ];
      i = p;
        }
    }

  _sinkDown(i) {
    const n = this.heap.length;
    while (true) {
      let min = i;
      const l = 2 * i + 1, r = 2 * i + 2;
      if (l < n && this.heap[l
            ].priority < this.heap[min
            ].priority) min = l;
      if (r < n && this.heap[r
            ].priority < this.heap[min
            ].priority) min = r;
      if (min === i) break;
      [this.heap[min
                ], this.heap[i
                ]
            ] = [this.heap[i
                ], this.heap[min
                ]
            ];
      i = min;
        }
    }
}

 // ─── Queue in Java ──────────────────────────────────────────────────────────
//
// java.util.Queue is an interface. Key implementations:
//   LinkedList     — O(1) offer/poll, general purpose
//   ArrayDeque     — O(1) amortized, faster than LinkedList in practice
//   PriorityQueue  — O(log n) offer/poll, heap-backed
//   ArrayBlockingQueue — thread-safe, bounded, for producer-consumer

import java.util.*;

public class QueueExamples {
    public static void main(String[] args) {
        // ── Simple queue (FIFO) via ArrayDeque ───────────────────────────
        Queue<Integer> queue = new ArrayDeque<>();
        queue.offer(10); // O(1) enqueue — returns false if full
        queue.offer(20);
        queue.offer(30);
        int front = queue.peek(); // O(1) peek — null if empty
        int val   = queue.poll(); // O(1) dequeue — null if empty
        boolean empty = queue.isEmpty(); // O(1)

        // ── Deque (double-ended) ─────────────────────────────────────────
        Deque<Integer> deque = new ArrayDeque<>();
        deque.offerFirst(5); // add to front
        deque.offerLast(10); // add to rear
        deque.pollFirst(); // remove from front
        deque.pollLast(); // remove from rear

        // ── Priority queue (min-heap) ─────────────────────────────────────
        PriorityQueue<Integer> pq = new PriorityQueue<>();
        pq.offer(30); // O(log n)
        pq.offer(10);
        pq.offer(20);
        int min = pq.poll(); // O(log n) → 10 (min element)

        // Max-heap using reverseOrder
        PriorityQueue<Integer> maxPQ = new PriorityQueue<>(Collections.reverseOrder());
        maxPQ.offer(30); maxPQ.offer(10); maxPQ.offer(20);
        int max = maxPQ.poll(); // → 30

        // ── BFS pattern (most common queue use-case) ──────────────────────
