    }
}

 // ─── Queue in C++ ───────────────────────────────────────────────────────────
//
// std::queue       — FIFO adapter over deque, O(1) push/pop
// std::deque       — double-ended, O(1) push/pop both ends
// std::priority_queue — max-heap by default, O(log n) push/pop
// boost::lockfree::queue — lock-free for concurrent use

#include <queue>
#include <deque>
#include <functional> // std::greater

int main() {
    // ── Simple queue (FIFO) ───────────────────────────────────────────────
    std::queue<int> q;
    q.push(10); // O(1) enqueue
    q.push(20);
    q.push(30);
    int front = q.front(); // O(1) peek
    q.pop(); // O(1) dequeue (no return value — call front() first)
    bool empty = q.empty(); // O(1)
    int  sz    = q.size(); // O(1)

    // ── Deque (double-ended) ──────────────────────────────────────────────
    std::deque<int> dq;
    dq.push_front(5); // O(1) add to front
    dq.push_back(10); // O(1) add to rear
    dq.pop_front(); // O(1) remove from front
    dq.pop_back(); // O(1) remove from rear

    // ── Priority queue — max-heap (default) ──────────────────────────────
    std::priority_queue<int> maxPQ;
    maxPQ.push(30); maxPQ.push(10); maxPQ.push(20);
    int top = maxPQ.top(); // 30 — O(1) peek
    maxPQ.pop(); // O(log n)

    // ── Priority queue — min-heap ─────────────────────────────────────────
    std::priority_queue<int, std::vector<int>, std::greater<int>> minPQ;
    minPQ.push(30); minPQ.push(10); minPQ.push(20);
    int minTop = minPQ.top(); // 10

    return 0;
}
